mapper.select:
SELECT rr.id, rr.employee_id, rr.residence_id, rr.`year_month`, rr.area, rr.unit_price,
       rr.days, rr.month_days, rr.amount, rr.status, rr.confirmed_at, rr.confirmed_by, rr.created_at
FROM rent_records rr
WHERE rr.is_deleted = 0

    AND rr.`year_month` = #{yearMonth}


    AND rr.employee_id = #{employeeId}


    AND rr.status = #{status}

ORDER BY rr.`year_month` DESC, rr.employee_id
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM rent_records rr
WHERE rr.is_deleted = 0

    AND rr.`year_month` = #{yearMonth}


    AND rr.employee_id = #{employeeId}


    AND rr.status = #{status}

SELECT COUNT(*)
FROM rent_records rr
WHERE rr.is_deleted = 0 AND rr.status = 'confirmed'

    AND rr.`year_month` = #{yearMonth}


    AND rr.employee_id = #{employeeId}

SELECT COALESCE(SUM(rr.amount), 0)
FROM rent_records rr
WHERE rr.is_deleted = 0

    AND rr.`year_month` = #{yearMonth}


    AND rr.employee_id = #{employeeId}
